55: // API represents an Alertmanager API v2.
56: type API struct {
57: 	peer           cluster.ClusterPeer
58: 	silences       *silence.Silences
59: 	alerts         provider.Alerts
60: 	alertGroups    groupsFn
61: 	getAlertStatus getAlertStatusFn
62: 	groupMutedFunc groupMutedFunc
63: 	uptime         time.Time
64: 
65: 	// mtx protects alertmanagerConfig, setAlertStatus and route.
66: 	mtx sync.RWMutex
67: 	// resolveTimeout represents the default resolve timeout that an alert is
68: 	// assigned if no end time is specified.
69: 	alertmanagerConfig *config.Config
70: 	route              *dispatch.Route
71: 	setAlertStatus     setAlertStatusFn
72: 
73: 	logger *slog.Logger
74: 	m      *metrics.Alerts
75: 
76: 	Handler http.Handler
77: }
78: 
79: type (
80: 	groupsFn         func(func(*dispatch.Route) bool, func(*types.Alert, time.Time) bool) (dispatch.AlertGroups, map[prometheus_model.Fingerprint][]string)
81: 	groupMutedFunc   func(routeID, groupKey string) ([]string, bool)
82: 	getAlertStatusFn func(prometheus_model.Fingerprint) types.AlertStatus
83: 	setAlertStatusFn func(prometheus_model.LabelSet)
84: )
