86: // NewAPI returns a new Alertmanager API v2.
87: func NewAPI(
88: 	alerts provider.Alerts,
89: 	gf groupsFn,
90: 	asf getAlertStatusFn,
91: 	gmf groupMutedFunc,
92: 	silences *silence.Silences,
93: 	peer cluster.ClusterPeer,
94: 	l *slog.Logger,
95: 	r prometheus.Registerer,
96: ) (*API, error) {
97: 	api := API{
98: 		alerts:         alerts,
99: 		getAlertStatus: asf,
100: 		alertGroups:    gf,
101: 		groupMutedFunc: gmf,
102: 		peer:           peer,
103: 		silences:       silences,
104: 		logger:         l,
105: 		m:              metrics.NewAlerts(r),
106: 		uptime:         time.Now(),
107: 	}
108: 
109: 	// Load embedded swagger file.
110: 	swaggerSpec, swaggerSpecAnalysis, err := getSwaggerSpec()
111: 	if err != nil {
112: 		return nil, err
113: 	}
114: 
115: 	// Create new service API.
116: 	openAPI := operations.NewAlertmanagerAPI(swaggerSpec)
117: 
118: 	// Skip the  redoc middleware, only serving the OpenAPI specification and
119: 	// the API itself via RoutesHandler. See:
120: 	// https://github.com/go-swagger/go-swagger/issues/1779
121: 	openAPI.Middleware = func(b middleware.Builder) http.Handler {
122: 		// Manually create the context so that we can use the singleton swaggerSpecAnalysis.
123: 		swaggerContext := middleware.NewRoutableContextWithAnalyzedSpec(swaggerSpec, swaggerSpecAnalysis, openAPI, nil)
124: 		return middleware.Spec("", swaggerSpec.Raw(), swaggerContext.RoutesHandler(b))
125: 	}
126: 
127: 	openAPI.AlertGetAlertsHandler = alert_ops.GetAlertsHandlerFunc(api.getAlertsHandler)
128: 	openAPI.AlertPostAlertsHandler = alert_ops.PostAlertsHandlerFunc(api.postAlertsHandler)
129: 	openAPI.AlertgroupGetAlertGroupsHandler = alertgroup_ops.GetAlertGroupsHandlerFunc(api.getAlertGroupsHandler)
130: 	openAPI.GeneralGetStatusHandler = general_ops.GetStatusHandlerFunc(api.getStatusHandler)
131: 	openAPI.ReceiverGetReceiversHandler = receiver_ops.GetReceiversHandlerFunc(api.getReceiversHandler)
132: 	openAPI.SilenceDeleteSilenceHandler = silence_ops.DeleteSilenceHandlerFunc(api.deleteSilenceHandler)
133: 	openAPI.SilenceGetSilenceHandler = silence_ops.GetSilenceHandlerFunc(api.getSilenceHandler)
134: 	openAPI.SilenceGetSilencesHandler = silence_ops.GetSilencesHandlerFunc(api.getSilencesHandler)
135: 	openAPI.SilencePostSilencesHandler = silence_ops.PostSilencesHandlerFunc(api.postSilencesHandler)
136: 
137: 	handleCORS := cors.Default().Handler
138: 	api.Handler = handleCORS(setResponseHeaders(openAPI.Serve(nil)))
139: 
140: 	return &api, nil
141: }
