170: func (api *API) getStatusHandler(params general_ops.GetStatusParams) middleware.Responder {
171: 	api.mtx.RLock()
172: 	defer api.mtx.RUnlock()
173: 
174: 	original := api.alertmanagerConfig.String()
175: 	uptime := strfmt.DateTime(api.uptime)
176: 
177: 	status := open_api_models.ClusterStatusStatusDisabled
178: 
179: 	resp := open_api_models.AlertmanagerStatus{
180: 		Uptime: &uptime,
181: 		VersionInfo: &open_api_models.VersionInfo{
182: 			Version:   &version.Version,
183: 			Revision:  &version.Revision,
184: 			Branch:    &version.Branch,
185: 			BuildUser: &version.BuildUser,
186: 			BuildDate: &version.BuildDate,
187: 			GoVersion: &version.GoVersion,
188: 		},
189: 		Config: &open_api_models.AlertmanagerConfig{
190: 			Original: &original,
191: 		},
192: 		Cluster: &open_api_models.ClusterStatus{
193: 			Status: &status,
194: 			Peers:  []*open_api_models.PeerStatus{},
195: 		},
196: 	}
197: 
198: 	// If alertmanager cluster feature is disabled, then api.peers == nil.
199: 	if api.peer != nil {
200: 		status := api.peer.Status()
201: 
202: 		peers := []*open_api_models.PeerStatus{}
203: 		for _, n := range api.peer.Peers() {
204: 			address := n.Address()
205: 			name := n.Name()
206: 			peers = append(peers, &open_api_models.PeerStatus{
207: 				Name:    &name,
208: 				Address: &address,
209: 			})
210: 		}
211: 
212: 		sort.Slice(peers, func(i, j int) bool {
213: 			return *peers[i].Name < *peers[j].Name
214: 		})
215: 
216: 		resp.Cluster = &open_api_models.ClusterStatus{
217: 			Name:   api.peer.Name(),
218: 			Status: &status,
219: 			Peers:  peers,
220: 		}
221: 	}
222: 
223: 	return general_ops.NewGetStatusOK().WithPayload(&resp)
224: }
