238: func (api *API) getAlertsHandler(params alert_ops.GetAlertsParams) middleware.Responder {
239: 	var (
240: 		receiverFilter *regexp.Regexp
241: 		// Initialize result slice to prevent api returning `null` when there
242: 		// are no alerts present
243: 		res = open_api_models.GettableAlerts{}
244: 		ctx = params.HTTPRequest.Context()
245: 
246: 		logger = api.requestLogger(params.HTTPRequest)
247: 	)
248: 
249: 	matchers, err := parseFilter(params.Filter)
250: 	if err != nil {
251: 		logger.Debug("Failed to parse matchers", "err", err)
252: 		return alertgroup_ops.NewGetAlertGroupsBadRequest().WithPayload(err.Error())
253: 	}
254: 
255: 	if params.Receiver != nil {
256: 		receiverFilter, err = regexp.Compile("^(?:" + *params.Receiver + ")$")
257: 		if err != nil {
258: 			logger.Debug("Failed to compile receiver regex", "err", err)
259: 			return alert_ops.
260: 				NewGetAlertsBadRequest().
261: 				WithPayload(
262: 					fmt.Sprintf("failed to parse receiver param: %v", err.Error()),
263: 				)
264: 		}
265: 	}
266: 
267: 	alerts := api.alerts.GetPending()
268: 	defer alerts.Close()
269: 
270: 	alertFilter := api.alertFilter(matchers, *params.Silenced, *params.Inhibited, *params.Active)
271: 	now := time.Now()
272: 
273: 	api.mtx.RLock()
274: 	for a := range alerts.Next() {
275: 		if err = alerts.Err(); err != nil {
276: 			break
277: 		}
278: 		if err = ctx.Err(); err != nil {
279: 			break
280: 		}
281: 
282: 		routes := api.route.Match(a.Labels)
283: 		receivers := make([]string, 0, len(routes))
284: 		for _, r := range routes {
285: 			receivers = append(receivers, r.RouteOpts.Receiver)
286: 		}
287: 
288: 		if receiverFilter != nil && !receiversMatchFilter(receivers, receiverFilter) {
289: 			continue
290: 		}
291: 
292: 		if !alertFilter(a, now) {
293: 			continue
294: 		}
295: 
296: 		alert := AlertToOpenAPIAlert(a, api.getAlertStatus(a.Fingerprint()), receivers, nil)
297: 
298: 		res = append(res, alert)
299: 	}
300: 	api.mtx.RUnlock()
301: 
302: 	if err != nil {
303: 		logger.Error("Failed to get alerts", "err", err)
304: 		return alert_ops.NewGetAlertsInternalServerError().WithPayload(err.Error())
305: 	}
306: 	sort.Slice(res, func(i, j int) bool {
307: 		return *res[i].Fingerprint < *res[j].Fingerprint
308: 	})
309: 
310: 	return alert_ops.NewGetAlertsOK().WithPayload(res)
311: }
