375: func (api *API) getAlertGroupsHandler(params alertgroup_ops.GetAlertGroupsParams) middleware.Responder {
376: 	logger := api.requestLogger(params.HTTPRequest)
377: 
378: 	matchers, err := parseFilter(params.Filter)
379: 	if err != nil {
380: 		logger.Debug("Failed to parse matchers", "err", err)
381: 		return alertgroup_ops.NewGetAlertGroupsBadRequest().WithPayload(err.Error())
382: 	}
383: 
384: 	var receiverFilter *regexp.Regexp
385: 	if params.Receiver != nil {
386: 		receiverFilter, err = regexp.Compile("^(?:" + *params.Receiver + ")$")
387: 		if err != nil {
388: 			logger.Error("Failed to compile receiver regex", "err", err)
389: 			return alertgroup_ops.
390: 				NewGetAlertGroupsBadRequest().
391: 				WithPayload(
392: 					fmt.Sprintf("failed to parse receiver param: %v", err.Error()),
393: 				)
394: 		}
395: 	}
396: 
397: 	rf := func(receiverFilter *regexp.Regexp) func(r *dispatch.Route) bool {
398: 		return func(r *dispatch.Route) bool {
399: 			receiver := r.RouteOpts.Receiver
400: 			if receiverFilter != nil && !receiverFilter.MatchString(receiver) {
401: 				return false
402: 			}
403: 			return true
404: 		}
405: 	}(receiverFilter)
406: 
407: 	af := api.alertFilter(matchers, *params.Silenced, *params.Inhibited, *params.Active)
408: 	alertGroups, allReceivers := api.alertGroups(rf, af)
409: 
410: 	res := make(open_api_models.AlertGroups, 0, len(alertGroups))
411: 
412: 	for _, alertGroup := range alertGroups {
413: 		mutedBy, isMuted := api.groupMutedFunc(alertGroup.RouteID, alertGroup.GroupKey)
414: 		if !*params.Muted && isMuted {
415: 			continue
416: 		}
417: 
418: 		ag := &open_api_models.AlertGroup{
419: 			Receiver: &open_api_models.Receiver{Name: &alertGroup.Receiver},
420: 			Labels:   ModelLabelSetToAPILabelSet(alertGroup.Labels),
421: 			Alerts:   make([]*open_api_models.GettableAlert, 0, len(alertGroup.Alerts)),
422: 		}
423: 
424: 		for _, alert := range alertGroup.Alerts {
425: 			fp := alert.Fingerprint()
426: 			receivers := allReceivers[fp]
427: 			status := api.getAlertStatus(fp)
428: 			apiAlert := AlertToOpenAPIAlert(alert, status, receivers, mutedBy)
429: 			ag.Alerts = append(ag.Alerts, apiAlert)
430: 		}
431: 		res = append(res, ag)
432: 	}
433: 
434: 	return alertgroup_ops.NewGetAlertGroupsOK().WithPayload(res)
435: }
