437: func (api *API) alertFilter(matchers []*labels.Matcher, silenced, inhibited, active bool) func(a *types.Alert, now time.Time) bool {
438: 	return func(a *types.Alert, now time.Time) bool {
439: 		if !a.EndsAt.IsZero() && a.EndsAt.Before(now) {
440: 			return false
441: 		}
442: 
443: 		// Set alert's current status based on its label set.
444: 		api.setAlertStatus(a.Labels)
445: 
446: 		// Get alert's current status after seeing if it is suppressed.
447: 		status := api.getAlertStatus(a.Fingerprint())
448: 
449: 		if !active && status.State == types.AlertStateActive {
450: 			return false
451: 		}
452: 
453: 		if !silenced && len(status.SilencedBy) != 0 {
454: 			return false
455: 		}
456: 
457: 		if !inhibited && len(status.InhibitedBy) != 0 {
458: 			return false
459: 		}
460: 
461: 		return alertMatchesFilterLabels(&a.Alert, matchers)
462: 	}
463: }
