465: func removeEmptyLabels(ls prometheus_model.LabelSet) {
466: 	for k, v := range ls {
467: 		if string(v) == "" {
468: 			delete(ls, k)
469: 		}
470: 	}
471: }
472: 
473: func receiversMatchFilter(receivers []string, filter *regexp.Regexp) bool {
474: 	for _, r := range receivers {
475: 		if filter.MatchString(r) {
476: 			return true
477: 		}
478: 	}
479: 
480: 	return false
481: }
482: 
483: func alertMatchesFilterLabels(a *prometheus_model.Alert, matchers []*labels.Matcher) bool {
484: 	sms := make(map[string]string)
485: 	for name, value := range a.Labels {
486: 		sms[string(name)] = string(value)
487: 	}
488: 	return matchFilterLabels(matchers, sms)
489: }
490: 
491: func matchFilterLabels(matchers []*labels.Matcher, sms map[string]string) bool {
492: 	for _, m := range matchers {
493: 		v, prs := sms[m.Name]
494: 		switch m.Type {
495: 		case labels.MatchNotRegexp, labels.MatchNotEqual:
496: 			if m.Value == "" && prs {
497: 				continue
498: 			}
499: 			if !m.Matches(v) {
500: 				return false
501: 			}
502: 		default:
503: 			if m.Value == "" && !prs {
504: 				continue
505: 			}
506: 			if !m.Matches(v) {
507: 				return false
508: 			}
509: 		}
510: 	}
511: 
512: 	return true
513: }
