515: func (api *API) getSilencesHandler(params silence_ops.GetSilencesParams) middleware.Responder {
516: 	logger := api.requestLogger(params.HTTPRequest)
517: 
518: 	matchers, err := parseFilter(params.Filter)
519: 	if err != nil {
520: 		logger.Debug("Failed to parse matchers", "err", err)
521: 		return silence_ops.NewGetSilencesBadRequest().WithPayload(err.Error())
522: 	}
523: 
524: 	psils, _, err := api.silences.Query()
525: 	if err != nil {
526: 		logger.Error("Failed to get silences", "err", err)
527: 		return silence_ops.NewGetSilencesInternalServerError().WithPayload(err.Error())
528: 	}
529: 
530: 	sils := open_api_models.GettableSilences{}
531: 	for _, ps := range psils {
532: 		if !CheckSilenceMatchesFilterLabels(ps, matchers) {
533: 			continue
534: 		}
535: 		silence, err := GettableSilenceFromProto(ps)
536: 		if err != nil {
537: 			logger.Error("Failed to unmarshal silence from proto", "err", err)
538: 			return silence_ops.NewGetSilencesInternalServerError().WithPayload(err.Error())
539: 		}
540: 		sils = append(sils, &silence)
541: 	}
542: 
543: 	SortSilences(sils)
544: 
545: 	return silence_ops.NewGetSilencesOK().WithPayload(sils)
546: }
547: 
548: var silenceStateOrder = map[types.SilenceState]int{
549: 	types.SilenceStateActive:  1,
550: 	types.SilenceStatePending: 2,
551: 	types.SilenceStateExpired: 3,
552: }
553: 
554: // SortSilences sorts first according to the state "active, pending, expired"
555: // then by end time or start time depending on the state.
556: // Active silences should show the next to expire first
557: // pending silences are ordered based on which one starts next
558: // expired are ordered based on which one expired most recently.
559: func SortSilences(sils open_api_models.GettableSilences) {
560: 	sort.Slice(sils, func(i, j int) bool {
561: 		state1 := types.SilenceState(*sils[i].Status.State)
562: 		state2 := types.SilenceState(*sils[j].Status.State)
563: 		if state1 != state2 {
564: 			return silenceStateOrder[state1] < silenceStateOrder[state2]
565: 		}
566: 		switch state1 {
567: 		case types.SilenceStateActive:
568: 			endsAt1 := time.Time(*sils[i].Silence.EndsAt)
569: 			endsAt2 := time.Time(*sils[j].Silence.EndsAt)
570: 			return endsAt1.Before(endsAt2)
571: 		case types.SilenceStatePending:
572: 			startsAt1 := time.Time(*sils[i].Silence.StartsAt)
573: 			startsAt2 := time.Time(*sils[j].Silence.StartsAt)
574: 			return startsAt1.Before(startsAt2)
575: 		case types.SilenceStateExpired:
576: 			endsAt1 := time.Time(*sils[i].Silence.EndsAt)
577: 			endsAt2 := time.Time(*sils[j].Silence.EndsAt)
578: 			return endsAt1.After(endsAt2)
579: 		}
580: 		return false
581: 	})
582: }
