584: // CheckSilenceMatchesFilterLabels returns true if
585: // a given silence matches a list of matchers.
586: // A silence matches a filter (list of matchers) if
587: // for all matchers in the filter, there exists a matcher in the silence
588: // such that their names, types, and values are equivalent.
589: func CheckSilenceMatchesFilterLabels(s *silencepb.Silence, matchers []*labels.Matcher) bool {
590: 	for _, matcher := range matchers {
591: 		found := false
592: 		for _, m := range s.Matchers {
593: 			if matcher.Name == m.Name &&
594: 				(matcher.Type == labels.MatchEqual && m.Type == silencepb.Matcher_EQUAL ||
595: 					matcher.Type == labels.MatchRegexp && m.Type == silencepb.Matcher_REGEXP ||
596: 					matcher.Type == labels.MatchNotEqual && m.Type == silencepb.Matcher_NOT_EQUAL ||
597: 					matcher.Type == labels.MatchNotRegexp && m.Type == silencepb.Matcher_NOT_REGEXP) &&
598: 				matcher.Value == m.Pattern {
599: 				found = true
600: 				break
601: 			}
602: 		}
603: 		if !found {
604: 			return false
605: 		}
606: 	}
607: 
608: 	return true
609: }
