125: // Mutes returns true iff the given label set is muted. It implements the Muter
126: // interface.
127: func (ih *Inhibitor) Mutes(lset model.LabelSet) bool {
128: 	fp := lset.Fingerprint()
129: 
130: 	for _, r := range ih.rules {
131: 		if !r.TargetMatchers.Matches(lset) {
132: 			// If target side of rule doesn't match, we don't need to look any further.
133: 			continue
134: 		}
135: 		// If we are here, the target side matches. If the source side matches, too, we
136: 		// need to exclude inhibiting alerts for which the same is true.
137: 		if inhibitedByFP, eq := r.hasEqual(lset, r.SourceMatchers.Matches(lset)); eq {
138: 			ih.marker.SetInhibited(fp, inhibitedByFP.String())
139: 			return true
140: 		}
141: 	}
142: 	ih.marker.SetInhibited(fp)
143: 
144: 	return false
145: }
